mapper.select:
SELECT r.id, r.book_id AS bookId, r.category_id AS categoryId, c.name AS categoryName, c.icon AS categoryIcon, r.type, r.amount, r.remark, DATE_FORMAT(r.record_date, '%Y-%m-%d') AS recordDate, DATE_FORMAT(r.record_time, '%H:%i') AS recordTime, DATE_FORMAT(r.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM t_record r LEFT JOIN t_category c ON r.category_id = c.id WHERE r.deleted = 0 AND r.user_id = #{userId}
AND r.book_id = #{bookId}
AND DATE_FORMAT(r.record_date, '%Y-%m') = #{yearMonth}
AND r.type = #{type}
ORDER BY r.record_date DESC, r.record_time DESC, r.id DESC

SELECT r.category_id AS categoryId, c.name AS categoryName, c.icon AS categoryIcon, r.type, SUM(r.amount) AS amount FROM t_record r LEFT JOIN t_category c ON r.category_id = c.id WHERE r.deleted = 0 AND r.user_id = #{userId} AND DATE_FORMAT(r.record_date, '%Y-%m') = #{yearMonth}
AND r.type = #{type}
GROUP BY r.category_id, c.name, c.icon, r.type ORDER BY amount DESC

SELECT
    DATE_FORMAT(r.record_date, '%Y-%m-%d') AS recordDate,
    SUM(r.amount) AS amount
FROM t_record r
WHERE r.deleted = 0
  AND r.user_id = #{userId}
  AND DATE_FORMAT(r.record_date, '%Y-%m') = #{yearMonth}

    AND r.type = #{type}

GROUP BY r.record_date
ORDER BY r.record_date ASC
